posts_db = {
    1: {
        "id": 1,
        "title": "First Post",
        "content": "This is the first post",
        "author_id": 1
    }
}

# GraphQL schema
type_defs = gql("""
    type User {
        id: ID!
        username: String!
        bio: String!
        email: String
        phone: String
        address: String
    }

    type Post {
        id: ID!
        title: String!
        content: String!
        author: User!
    }

    type Query {
        getUser(id: ID!): User
        getPosts: [Post!]!
        currentUser: User
    }
""")

# Resolvers
query = QueryType()

@query.field("getUser")
def resolve_get_user(_, info, id):
    user = users_db.get(int(id))
    if user:
        return user
    return None

@query.field("getPosts")
def resolve_get_posts(_, info):
    return posts_db.values()

@query.field("currentUser")
def resolve_current_user(_, info):
    if hasattr(g, 'current_user') and g.current_user:
        return g.current_user
    return None

# User object type for post resolution
user = ObjectType("User")

@user.field("id")
def resolve_user_id(user_obj, info):
    return user_obj["id"]

@user.field("username")
def resolve_user_username(user_obj, info):
    return user_obj["username"]

@user.field("bio")
def resolve_user_bio(user_obj, info):
    return user_obj["bio"]

@user.field("email")
def resolve_user_email(user_obj, info):
    return user_obj.get("email")

@user.field("phone")
def resolve_user_phone(user_obj, info):
    return user_obj.get("phone")

@user.field("address")
def resolve_user_address(user_obj, info):
    return user_obj.get("address")

# Post object type
post = ObjectType("Post")

@post.field("id")
def resolve_post_id(post_obj, info):
    return post_obj["id"]

@post.field("title")
def resolve_post_title(post_obj, info):
    return post_obj["title"]

@post.field("content")
def resolve_post_content(post_obj, info):
    return post_obj["content"]

@post.field("author")
def resolve_post_author(post_obj, info):
    author_id = post_obj["author_id"]
    return users_db.get(author_id)

# Schema
schema = make_executable_schema(type_defs, [query, user, post])

# Flask app with authentication middleware
app = Flask(__name__)

def auth_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        # Mock authentication - in real app, check JWT or session
        auth_header = request.headers.get('Authorization')
        if auth_header and auth_header.startswith('Bearer '):
            token = auth_header.split(' ')[1]
            # Mock user lookup
            if token == "valid_token_123":
                g.current_user = users_db[1]  # Set to first user for demo
            else:
                g.current_user = None
        else:
            g.current_user = None
        return f(*args, **kwargs)
    return decorated_function

@app.route("/graphql", methods=["GET", "POST"])
@auth_required
def graphql_server():
    if request.method == "GET":
        return PLAYGROUND_HTML, 200
    elif request.method == "POST":
        data = request.get_json()
        if not data:
            return jsonify({"error": "No data provided"}), 400
        
        result = schema.execute(data.get("query"), variable_values=data.get("variables"))
        return jsonify(result)

if __name__ == "__main__":
    app.run(debug=True)